import React, { useState, useEffect } from 'react';
import {
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Switch,
  FormControlLabel
} from '@mui/material';
import InboxIcon from '@mui/icons-material/Inbox';
import HomeIcon from '@mui/icons-material/Home';
import LoginIcon from '@mui/icons-material/Login';

const drawerWidth = 240;

function NavigationDrawer() {
  const [theme, setTheme] = useState('light');

  // Load the saved theme from localStorage
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme');
    if (savedTheme) {
      setTheme(savedTheme);
      document.body.className = savedTheme; // Apply saved theme
    }
  }, []);

  // Toggle between light and dark mode
  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme); // Save to localStorage
    document.body.className = newTheme; // Apply theme
  };

  return (
    <Drawer
      variant="permanent"
      sx={{
        width: drawerWidth,
        flexShrink: 0,
        [`& .MuiDrawer-paper`]: { width: drawerWidth, boxSizing: 'border-box' },
      }}
    >
      <List>
        <ListItem button key="Inbox">
          <ListItemIcon><InboxIcon /></ListItemIcon>
          <ListItemText primary="Inbox" />
        </ListItem>
        <ListItem button key="Home">
          <ListItemIcon><HomeIcon /></ListItemIcon>
          <ListItemText primary="Home" />
        </ListItem>
        <ListItem button key="Studio">
          <ListItemIcon><HomeIcon /></ListItemIcon>
          <ListItemText primary="Studio" />
        </ListItem>
        <ListItem button key="FileManager">
          <ListItemIcon><HomeIcon /></ListItemIcon>
          <ListItemText primary="File Manager" />
        </ListItem>
        <ListItem button key="Setup">
          <ListItemIcon><HomeIcon /></ListItemIcon>
          <ListItemText primary="Setup" />
        </ListItem>
      </List>
      <List sx={{ marginTop: 'auto' }}>
        <ListItem button key="Login">
          <ListItemIcon><LoginIcon /></ListItemIcon>
          <ListItemText primary="Login" />
        </ListItem>
        {/* Add Light/Dark Mode Toggle */}
        <ListItem key="ThemeToggle">
          <FormControlLabel
            control={<Switch checked={theme === 'dark'} onChange={toggleTheme} />}
            label={`${theme === 'light' ? 'Light' : 'Dark'} Mode`}
            sx={{ marginLeft: 1 }}
          />
        </ListItem>
      </List>
    </Drawer>
  );
}

export default NavigationDrawer;
